        // Data stored in the node
        this.data = data1;
        // Pointer to the next node in the list
        this.next = next1;
    }
}

// Function to convert an array to a linked list
function convertArrToLinkedList(arr) {
    // Create a dummy node to serve
    // as the head of the linked list
    const dummyNode = new Node(-1);
    let temp = dummyNode;

    // Iterate through the array and
    // create nodes with array elements
    for (let i = 0; i &lt; arr.length; i++) {
        // Create a new node with the array element
        temp.next = new Node(arr[i]);
        // Move the temporary pointer
        // to the newly created node
        temp = temp.next;
    }

    // Return the linked list starting
    // from the next of the dummy node
    return dummyNode.next;
}

// Function to merge two sorted linked lists
function sortTwoLinkedLists(list1, list2) {
    const arr = [];
    let temp1 = list1;
    let temp2 = list2;

    // Storing elements of both lists into an array

    // Add elements from list1 to the array
    while (temp1 !== null) {
        arr.push(temp1.data);
        // Move to the next node in list1
        temp1 = temp1.next;
    }

    // Add elements from list2 to the array
    while (temp2 !== null) {
        arr.push(temp2.data);
        // Move to the next node in list2
        temp2 = temp2.next;
    }

    // Sorting the array in ascending order
    arr.sort((a, b) =&gt; a - b);

    // Converting the sorted array
    // back to a linked list
    const head = convertArrToLinkedList(arr);

    // Return the head of the
    // merged sorted linked list
    return head;
}

